#include <iostream>
#include <string.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <arpa/inet.h>

const int BUFFER_SIZE = 256;
char logBuffer[BUFFER_SIZE];

int main() {
    // Create a socket
    int sock = socket(AF_INET, SOCK_STREAM, 0);
    if (sock < 0) {
        std::cerr << "Error creating socket" << std::endl;
        return 1;
    }

    // Bind the socket to a specific address and port
    sockaddr_in addr;
    addr.sin_family = AF_INET;
    addr.sin_port = htons(8080);
    inet_pton(AF_INET, "127.0.0.1", &addr.sin_addr);
    if (bind(sock, (struct sockaddr*)&addr, sizeof(addr)) < 0) {
        std::cerr << "Error binding socket" << std::endl;
        return 1;
    }

    // Listen for incoming connections
    if (listen(sock, 3) < 0) {
        std::cerr << "Error listening on socket" << std::endl;
        return 1;
    }

    // Accept an incoming connection
    int clientSock = accept(sock, NULL, NULL);
    if (clientSock < 0) {
        std::cerr << "Error accepting incoming connection" << std::endl;
        return 1;
    }

    // Receive a message from the client
    char buffer[BUFFER_SIZE];
    int bytesReceived = recv(clientSock, buffer, BUFFER_SIZE, 0);
    if (bytesReceived < 0) {
        std::cerr << "Error receiving message" << std::endl;
        return 1;
    }

    // Copy the received message to the log buffer
    strcpy(logBuffer, buffer);

    // Close the client socket
    close(clientSock);

    // Log the received message
    std::cout << "Received message: " << logBuffer << std::endl;

    return 0;
}